article_to_region = {rec['article_id']: rec['region'] for rec in metadata_2015}

print('__RESULT__:')
print(json.dumps({
    'total_2015_articles': len(article_ids_2015),
    'article_id_range': f"{min(article_ids_2015)} to {max(article_ids_2015)}",
    'region_counts': {region: sum(1 for rec in metadata_2015 if rec['region'] == region) 
                     for region in sorted(set(article_to_region.values()))}
}))"}

