{"code": "import json

# Load metadata
with open(locals()['var_functions.query_db:5'], 'r') as f:
    metadata_2015 = json.load(f)

# Create article_id to region mapping
article_to_region = {rec['article_id']: rec['region'] for rec in metadata_2015}

# Build MongoDB queries for all batches
batch_size = 200
batches = []
article_ids = list(article_to_region.keys())

for i in range(0, len(article_ids), batch_size):
    batch_ids = article_ids[i:i+batch_size]
    query = {
        "collection": "articles",
        "filter": {"article_id": {"$in": batch_ids}},
        "limit": batch_size
    }
    batches.append(query)

print('__RESULT__:')
print(json.dumps({
    'total_batches': len(batches),
    'first_query': batches[0]
}))"}

